def tier_rows(rows):
    out = []
    for r in rows:
        score = r.get("score", 0)
        if score >= 85:
            tier = "A"
        elif score >= 70:
            tier = "B"
        else:
            tier = "C"
        out.append({
            "lead_id": r.get("lead_id", ""),
            "company": r.get("company", ""),
            "region": r.get("region", ""),
            "score": score,
            "stage": r.get("stage", ""),
            "tier": tier,
            "qualified": tier == "A" or tier == "B",
        })
    return out

